draw((0,-2.5)--(0,2.5));

draw((1,-0.1)--(1,0.1));
draw((2,-0.1)--(2,0.1));
draw((-1,-0.1)--(-1,0.1));
draw((-2,-0.1)--(-2,0.1));
draw((-0.1,1)--(0.1,1));
